1	/**
2	 * Synth editor panel: oscillator type selectors, filter cutoff/resonance knobs,
3	 * ADSR sliders, LFO rate/depth knobs.
4	 * Neo-brutalist styling consistent with the design system.
5	 */
6	
7	import { useCallback } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	import { useSynthStore } from "@state/synth";
10	import { VirtualKeyboard } from "./VirtualKeyboard";
11	import { ModulationMatrix } from "./ModulationMatrix";
12	import type { SynthParameterMap } from "@audio/synth/synth-types";
13	import {
14	  WAVEFORM_TYPES,
15	  FILTER_TYPES,
16	  LFO_SHAPES,
17	} from "@audio/synth/synth-types";
18	
19	type SynthEditorProps = {
20	  trackId: string;
21	  onNoteOn?: (note: number, velocity: number) => void;
22	  onNoteOff?: (note: number) => void;
23	};
24	
25	// ─── Shared Styles ───
26	
27	const BORDER = "var(--border)";
28	
29	const sectionStyle: React.CSSProperties = {
30	  border: BORDER,
31	  padding: tokens.space[2],
32	  display: "flex",
33	  flexDirection: "column",
34	  gap: tokens.space[1],
35	};
36	
37	const labelStyle: React.CSSProperties = {
38	  fontFamily: tokens.font.mono,
39	  fontSize: tokens.text.xs,
40	  color: tokens.color.gray300,
41	  textTransform: "uppercase",
42	  letterSpacing: "0.1em",
43	};
44	
45	const controlRowStyle: React.CSSProperties = {
46	  display: "flex",
47	  gap: tokens.space[2],
48	  alignItems: "center",
49	};
50	
51	// ─── Reusable Controls ───
52	
53	function Knob({
54	  label,
55	  value,
56	  min,
57	  max,
58	  step,
59	  unit,
60	  onChange,
61	}: {
62	  label: string;
63	  value: number;
64	  min: number;
65	  max: number;
66	  step: number;
67	  unit?: string;
68	  onChange: (v: number) => void;
69	}): React.JSX.Element {
70	  return (
71	    <div
72	      style={{
73	        display: "flex",
74	        flexDirection: "column",
75	        alignItems: "center",
76	        gap: 2,
77	      }}
78	    >
79	      <span style={labelStyle}>{label}</span>
80	      <input
81	        type="range"
82	        min={min}
83	        max={max}
84	        step={step}
85	        value={value}
86	        onChange={(e) => {
87	          onChange(Number(e.target.value));
88	        }}
89	        style={{ width: 60, accentColor: tokens.color.blue }}
90	        data-testid={"knob-" + label.toLowerCase().replace(/\s/g, "-")}
91	      />
92	      <span style={{ ...labelStyle, fontSize: tokens.text["2xs"] }}>
93	        {value.toFixed(step < 1 ? 2 : 0)}
94	        {unit ?? ""}
95	      </span>
96	    </div>
97	  );
98	}
99	
100	function TypeSelector<T extends string>({
101	  label,
102	  value,
103	  options,
104	  onChange,
105	}: {
106	  label: string;
107	  value: T;
108	  options: readonly T[];
109	  onChange: (v: T) => void;
110	}): React.JSX.Element {
111	  return (
112	    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
113	      <span style={labelStyle}>{label}</span>
114	      <select
115	        value={value}
116	        onChange={(e) => {
117	          onChange(e.target.value as T);
118	        }}
119	        data-testid={"select-" + label.toLowerCase().replace(/\s/g, "-")}
120	        style={{
121	          backgroundColor: tokens.color.gray900,
122	          color: tokens.color.gray100,
123	          border: BORDER,
124	          fontFamily: tokens.font.mono,
125	          fontSize: tokens.text.xs,
126	          padding: "2px 4px",
127	        }}
128	      >
129	        {options.map((opt) => (
130	          <option key={opt} value={opt}>
