213	                set("osc1Octave", v);
214	              }}
215	            />
216	            <Knob
217	              label="Detune"
218	              value={p.osc1Detune}
219	              min={-100}
220	              max={100}
221	              step={1}
222	              unit="c"
223	              onChange={(v) => {
224	                set("osc1Detune", v);
225	              }}
226	            />
227	            <Knob
228	              label="Level"
229	              value={p.osc1Level}
230	              min={0}
231	              max={1}
232	              step={0.01}
233	              onChange={(v) => {
234	                set("osc1Level", v);
235	              }}
236	            />
237	          </div>
238	        </section>
239	
240	        {/* OSC 2 */}
241	        <section style={sectionStyle} data-testid="osc2-section">
242	          <span style={{ ...labelStyle, color: tokens.color.pink }}>OSC 2</span>
243	          <div style={controlRowStyle}>
244	            <TypeSelector
245	              label="Type"
246	              value={p.osc2Type}
247	              options={WAVEFORM_TYPES}
248	              onChange={(v) => {
249	                set("osc2Type", v);
250	              }}
251	            />
252	            <Knob
253	              label="Oct"
254	              value={p.osc2Octave}
255	              min={-2}
256	              max={2}
257	              step={1}
258	              onChange={(v) => {
259	                set("osc2Octave", v);
