1	import type { WaveformPeaks } from "./types";
2	
3	/**
4	 * Compute min/max peak pairs from an AudioBuffer.
5	 * Uses max absolute across all channels for multi-channel buffers.
6	 */
7	export function computeWaveformPeaks(
8	  buffer: AudioBuffer,
9	  samplesPerPeak: number,
10	  sourceId = "",
11	): WaveformPeaks {
12	  if (samplesPerPeak <= 0) {
13	    return { sourceId, samplesPerPeak, peaks: new Float32Array(0), length: 0 };
14	  }
15	  const totalSamples = buffer.length;
16	  const numPeaks = Math.ceil(totalSamples / samplesPerPeak);
17	  const peaks = new Float32Array(numPeaks * 2);
18	
19	  for (let p = 0; p < numPeaks; p++) {
20	    const start = p * samplesPerPeak;
21	    const end = Math.min(start + samplesPerPeak, totalSamples);
22	    let min = Infinity;
23	    let max = -Infinity;
24	
25	    for (let ch = 0; ch < buffer.numberOfChannels; ch++) {
26	      const channelData = buffer.getChannelData(ch);
27	      for (let i = start; i < end; i++) {
28	        const sample = channelData[i] ?? 0;
29	        if (sample < min) min = sample;
30	        if (sample > max) max = sample;
31	      }
32	    }
33	
34	    peaks[p * 2] = min;
35	    peaks[p * 2 + 1] = max;
36	  }
37	
38	  return { sourceId, samplesPerPeak, peaks, length: numPeaks };
39	}
