1	import { useRef, useEffect } from "react";
2	import type { WaveformPeaks } from "@audio/media-pool";
3	
4	type WaveformPreviewProps = {
5	  peaks: WaveformPeaks;
6	  width?: number;
7	  height?: number;
8	};
9	
10	export function WaveformPreview({
11	  peaks,
12	  width = 120,
13	  height = 24,
14	}: WaveformPreviewProps): React.JSX.Element {
15	  const canvasRef = useRef<HTMLCanvasElement>(null);
16	
17	  useEffect(() => {
18	    const canvas = canvasRef.current;
19	    if (canvas === null) return;
20	    const ctx = canvas.getContext("2d");
21	    if (ctx === null) return;
22	
23	    ctx.clearRect(0, 0, width, height);
24	
25	    const numPeaks = peaks.length;
26	    if (numPeaks === 0) return;
27	
28	    const mid = height / 2;
29	    const barWidth = width / numPeaks;
30	
31	    ctx.fillStyle =
32	      getComputedStyle(canvas).getPropertyValue("--color-blue").trim() ||
33	      "#0066ff";
34	
35	    for (let i = 0; i < numPeaks; i++) {
36	      const min = peaks.peaks[i * 2] ?? 0;
37	      const max = peaks.peaks[i * 2 + 1] ?? 0;
38	      const x = i * barWidth;
39	      const top = mid - max * mid;
40	      const bottom = mid - min * mid;
41	      ctx.fillRect(x, top, Math.max(barWidth - 0.5, 0.5), bottom - top);
42	    }
43	  }, [peaks, width, height]);
44	
45	  return (
46	    <canvas
47	      ref={canvasRef}
48	      width={width}
49	      height={height}
50	      role="img"
51	      aria-label="Waveform"
52	      style={{ display: "block", width, height }}
53	    />
54	  );
55	}
