30	export function MediaPoolPanel({
31	  pool,
32	}: MediaPoolPanelProps): React.JSX.Element {
33	  const fileInputRef = useRef<HTMLInputElement>(null);
34	  const [version, setVersion] = useState(0);
35	  const sources = useMemo(() => pool.listSources(), [pool, version]); // eslint-disable-line react-hooks/exhaustive-deps
36	  const [peaksMap, setPeaksMap] = useState(new Map<string, WaveformPeaks>());
37	  const [errors, setErrors] = useState<MediaPoolError[]>([]);
38	  const [removeError, setRemoveError] = useState<string | null>(null);
39	  const [isImporting, setIsImporting] = useState(false);
40	  const [undoPending, setUndoPending] = useState<UndoToastState | null>(null);
41	  const [pendingRemoveId, setPendingRemoveId] = useState<string | null>(null);
42	  const importingRef = useRef(false);
43	  const autoDismissTimerRef = useRef(0);
44	
45	  useEffect(() => {
46	    // Load cached peaks for persisted sources
47	    void Promise.all(
48	      sources.map(async (source) => {
49	        if (peaksMap.has(source.id)) return;
50	        const peaks = await pool.getPeaks(source.id, 256);
51	        if (peaks !== undefined) {
52	          setPeaksMap((prev) => {
53	            const next = new Map(prev);
54	            next.set(source.id, peaks);
55	            return next;
56	          });
57	        }
58	      }),
59	    );
60	  }, [sources, pool]); // eslint-disable-line react-hooks/exhaustive-deps
61	
62	  const handleImport = useCallback(
63	    async (files: File[]) => {
64	      if (importingRef.current) return;
65	      importingRef.current = true;
66	      setIsImporting(true);
67	      setErrors([]);
68	      window.clearTimeout(autoDismissTimerRef.current);
69	      try {
70	        const importErrors: MediaPoolError[] = [];
71	        for (const file of files) {
72	          const result = await pool.importFile(file);
73	          if (result.ok) {
74	            const peaks = await pool.getPeaks(result.handle.id, 256);
75	            if (peaks !== undefined) {
76	              setPeaksMap((prev) => {
77	                const next = new Map(prev);
78	                next.set(result.handle.id, peaks);
79	                return next;
80	              });
81	            }
82	          } else {
83	            importErrors.push(result.error);
84	          }
85	        }
86	        if (importErrors.length > 0) {
87	          setErrors(importErrors);
88	          autoDismissTimerRef.current = window.setTimeout(() => {
89	            setErrors([]);
90	          }, 5000);
91	        }
92	        setVersion((v) => v + 1);
93	      } finally {
94	        importingRef.current = false;
95	        setIsImporting(false);
96	      }
97	    },
98	    [pool],
99	  );
100	
101	  const executeRemove = useCallback(
102	    (id: string) => {
103	      void pool
104	        .removeSource(id)
105	        .then(() => {
106	          setVersion((v) => v + 1);
107	          setPeaksMap((prev) => {
108	            const next = new Map(prev);
109	            next.delete(id);
110	            return next;
111	          });
112	        })
113	        .catch(() => {
114	          const name = pool.getSource(id)?.name ?? id;
115	          setRemoveError(`Failed to remove "${name}".`);
116	        });
117	    },
118	    [pool],
119	  );
120	
121	  const handleRemove = useCallback(
122	    (id: string) => {
123	      const name = pool.getSource(id)?.name ?? id;
124	      setPendingRemoveId(id);
125	      setUndoPending({
126	        message: `Removed "${name}".`,
127	        onUndo: () => {
128	          setPendingRemoveId(null);
129	          setUndoPending(null);
130	        },
131	      });
132	    },
133	    [pool],
134	  );
135	
136	  const handleUndoExpired = useCallback(() => {
137	    setPendingRemoveId((prev) => {
138	      if (prev !== null) {
139	        executeRemove(prev);
140	      }
141	      return null;
142	    });
143	    setUndoPending(null);
144	  }, [executeRemove]);
145	
146	  const onFileDrop = useCallback(
147	    (files: File[]) => {
148	      void handleImport(files);
149	    },
150	    [handleImport],
151	  );
152	
153	  const { isDragging, handlers } = useFileDrop(onFileDrop);
154	
155	  const onImportClick = useCallback(() => {
156	    fileInputRef.current?.click();
157	  }, []);
158	
159	  const onFileChange = useCallback(
160	    (e: React.ChangeEvent<HTMLInputElement>) => {
161	      const files = e.target.files;
162	      if (files !== null && files.length > 0) {
163	        void handleImport([...files]);
164	      }
165	    },
166	    [handleImport],
167	  );
168	
169	  const panelClass = isDragging
170	    ? [styles["panel"], styles["dragging"]].join(" ")
171	    : (styles["panel"] ?? "");
172	
173	  return (
174	    <section
175	      data-testid="media-pool-panel"
176	      className={panelClass}
177	      {...handlers}
178	    >
179	      <div className={styles["header"]}>
180	        <span>MEDIA POOL</span>
181	        <button
182	          type="button"
183	          className={styles["importBtn"]}
184	          onClick={onImportClick}
185	          disabled={isImporting}
186	        >
187	          {isImporting ? "IMPORTING..." : "IMPORT"}
188	        </button>
189	        <input
190	          ref={fileInputRef}
191	          type="file"
192	          accept="audio/wav,audio/mpeg,audio/ogg,audio/flac,.wav,.mp3,.ogg,.flac"
193	          multiple
194	          style={{ display: "none" }}
195	          onChange={onFileChange}
196	        />
197	      </div>
198	
199	      {(errors.length > 0 || removeError !== null) && (
200	        <div className={styles["error"]}>
201	          {errors.map((err, i) => (
202	            <div key={i}>{formatError(err)}</div>
203	          ))}
204	          {removeError !== null && <div>{removeError}</div>}
205	          <button
206	            type="button"
207	            className={styles["dismissBtn"]}
208	            onClick={() => {
209	              window.clearTimeout(autoDismissTimerRef.current);
210	              setErrors([]);
211	              setRemoveError(null);
212	            }}
213	            aria-label="Dismiss errors"
214	          >
215	            Dismiss
216	          </button>
217	        </div>
218	      )}
219	
220	      {isImporting && (
221	        <div className={styles["importing"]}>
222	          <Spinner />
223	          <span>Importing audio...</span>
224	        </div>
225	      )}
226	
227	      {sources.length === 0 ? (
228	        <div className={styles["empty"]}>
229	          Drop audio files here or click IMPORT
230	        </div>
231	      ) : (
232	        <div className={styles["list"]}>
233	          {sources
234	            .filter((s) => s.id !== pendingRemoveId)
235	            .map((source) => (
236	              <MediaPoolItem
237	                key={source.id}
238	                source={source}
239	                peaks={peaksMap.get(source.id)}
240	                onRemove={handleRemove}
241	              />
242	            ))}
243	        </div>
244	      )}
245	      <UndoToast pending={undoPending} onExpired={handleUndoExpired} />
246	    </section>
247	  );
248	}
