1	import { useRef, useEffect, useCallback, useState } from "react";
2	import { tokens } from "../tokens/tokens";
3	import styles from "./RotaryKnob.module.css";
4	
5	type RotaryKnobProps = {
6	  value: number;
7	  min: number;
8	  max: number;
9	  step?: number;
10	  onChange: (value: number) => void;
11	  label: string;
12	  size?: number;
13	  valueText?: string;
14	};
15	
16	const START_ANGLE = 0.75 * Math.PI;
17	const END_ANGLE = 2.25 * Math.PI;
18	const ARC_RANGE = END_ANGLE - START_ANGLE;
19	const DRAG_SENSITIVITY = 200;
20	
21	function clamp(v: number, min: number, max: number): number {
22	  return Math.min(max, Math.max(min, v));
23	}
24	
25	function snapToStep(raw: number, step: number): number {
26	  return Math.round(raw / step) * step;
27	}
28	
29	function drawKnob(
30	  ctx: CanvasRenderingContext2D,
31	  size: number,
32	  ratio: number,
33	  hovered: boolean,
34	): void {
35	  const cx = size / 2;
36	  const cy = size / 2;
37	  const radius = size / 2 - tokens.border.width * 2;
38	
39	  ctx.clearRect(0, 0, size, size);
40	
41	  // Outer circle (highlight on hover)
42	  ctx.beginPath();
43	  ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
44	  ctx.strokeStyle = hovered ? tokens.color.gray500 : tokens.color.gray700;
45	  ctx.lineWidth = tokens.border.width;
46	  ctx.stroke();
47	
48	  // Value arc
49	  const valueAngle = START_ANGLE + ratio * ARC_RANGE;
50	  ctx.beginPath();
51	  ctx.arc(cx, cy, radius, START_ANGLE, valueAngle);
52	  ctx.strokeStyle = tokens.color.blue;
53	  ctx.lineWidth = tokens.border.width + 1;
54	  ctx.lineCap = "round";
55	  ctx.stroke();
56	
57	  // Pointer line from center
58	  const pointerLen = radius * 0.7;
59	  const px = cx + Math.cos(valueAngle) * pointerLen;
60	  const py = cy + Math.sin(valueAngle) * pointerLen;
61	  ctx.beginPath();
62	  ctx.moveTo(cx, cy);
63	  ctx.lineTo(px, py);
64	  ctx.strokeStyle = tokens.color.white;
65	  ctx.lineWidth = tokens.border.width;
66	  ctx.lineCap = "round";
67	  ctx.stroke();
68	}
69	
70	export function RotaryKnob({
71	  value,
72	  min,
73	  max,
74	  step = 1,
75	  onChange,
76	  label,
77	  size = 48,
78	  valueText,
79	}: RotaryKnobProps): React.JSX.Element {
80	  const canvasRef = useRef<HTMLCanvasElement>(null);
81	  const wrapperRef = useRef<HTMLDivElement>(null);
82	  const listenersRef = useRef<AbortController | null>(null);
83	  const [isHovered, setIsHovered] = useState(false);
84	
85	  const ratio = max === min ? 0 : (value - min) / (max - min);
86	
87	  useEffect(() => {
88	    const canvas = canvasRef.current;
89	    if (!canvas) return;
90	    const ctx = canvas.getContext("2d");
91	    if (!ctx) return;
92	    drawKnob(ctx, size, ratio, isHovered);
93	  }, [value, min, max, size, ratio, isHovered]);
94	
95	  // Cleanup drag listeners on unmount
96	  useEffect(() => {
97	    return (): void => {
98	      listenersRef.current?.abort();
99	    };
100	  }, []);
101	
102	  const commit = useCallback(
103	    (next: number): void => {
104	      onChange(clamp(snapToStep(next, step), min, max));
105	    },
106	    [onChange, min, max, step],
107	  );
108	
109	  const handleKeyDown = useCallback(
110	    (e: React.KeyboardEvent): void => {
111	      switch (e.key) {
112	        case "ArrowUp":
113	        case "ArrowRight":
114	          e.preventDefault();
115	          commit(value + step);
116	          break;
117	        case "ArrowDown":
118	        case "ArrowLeft":
119	          e.preventDefault();
120	          commit(value - step);
121	          break;
122	        case "PageUp":
123	          e.preventDefault();
124	          commit(value + step * 10);
125	          break;
126	        case "PageDown":
127	          e.preventDefault();
128	          commit(value - step * 10);
129	          break;
130	        case "Home":
131	          e.preventDefault();
132	          commit(min);
133	          break;
134	        case "End":
135	          e.preventDefault();
136	          commit(max);
137	          break;
138	      }
139	    },
140	    [value, step, min, max, commit],
141	  );
142	
143	  const handlePointerDown = useCallback(
144	    (e: React.PointerEvent): void => {
145	      e.preventDefault();
146	      const target = e.target as HTMLElement;
147	      if (typeof target.setPointerCapture === "function") {
148	        target.setPointerCapture(e.pointerId);
149	      }
150	      const startY = e.clientY;
151	      const startValue = value;
152	      const range = max - min;
153	
154	      listenersRef.current?.abort();
155	      const controller = new AbortController();
156	      listenersRef.current = controller;
157	
158	      document.addEventListener(
159	        "pointermove",
160	        (moveEvent: PointerEvent) => {
161	          const delta = startY - moveEvent.clientY;
162	          const fraction = delta / DRAG_SENSITIVITY;
163	          commit(startValue + fraction * range);
164	        },
165	        { signal: controller.signal },
166	      );
167	
168	      document.addEventListener(
169	        "pointerup",
170	        () => {
171	          controller.abort();
172	        },
173	        { signal: controller.signal },
174	      );
175	    },
176	    [value, max, min, commit],
177	  );
178	
179	  return (
180	    <div
181	      ref={wrapperRef}
182	      className={styles.knob}
183	      role="slider"
184	      tabIndex={0}
185	      aria-valuemin={min}
186	      aria-valuemax={max}
187	      aria-valuenow={value}
188	      aria-valuetext={valueText}
189	      aria-label={label}
190	      onKeyDown={handleKeyDown}
191	      onPointerEnter={() => {
192	        setIsHovered(true);
193	      }}
194	      onPointerLeave={() => {
195	        setIsHovered(false);
196	      }}
197	      style={{
198	        display: "inline-flex",
199	        flexDirection: "column",
200	        alignItems: "center",
201	        gap: tokens.space[1],
202	        userSelect: "none",
203	      }}
204	    >
205	      <span
206	        style={{
207	          fontSize: tokens.text.xs,
208	          fontFamily: tokens.font.mono,
209	          color: tokens.color.gray300,
210	        }}
211	      >
212	        {label}
213	      </span>
214	      <canvas
215	        ref={canvasRef}
216	        width={size}
217	        height={size}
218	        onPointerDown={handlePointerDown}
219	        style={{ cursor: "grab" }}
220	      />
221	      <span
222	        style={{
223	          fontSize: tokens.text.xs,
224	          fontFamily: tokens.font.mono,
225	          color: tokens.color.white,
226	        }}
227	      >
228	        {value}
229	      </span>
230	    </div>
231	  );
232	}
