1	/**
2	 * Pure canvas renderer for the arrangement view.
3	 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
4	 */
5	import type { TrackModel, ClipModel } from "@state/track/types";
6	import type { AutomationLane } from "@audio/automation/automation-types";
7	import { evaluateCurve } from "@audio/automation/automation-curve";
8	import { RULER_HEIGHT, CLIP_PADDING } from "./constants";
9	
10	// -- Design token constants (canvas cannot read CSS vars) ---------------------
11	
12	const COLOR = {
13	  black: "#000000",
14	  white: "#ffffff",
15	  red: "#ff0000",
16	  pink: "#ff2d6f",
17	  gray900: "#111111",
18	  gray700: "#333333",
19	  gray500: "#666666",
20	} as const;
21	
22	const FONT_MONO = "'JetBrains Mono', monospace" as const;
23	const TEXT_XS = 10;
24	const TEXT_SM = 12;
25	const BORDER_WIDTH = 2;
26	const COLOR_STRIP_WIDTH = 4;
27	
28	// -- Public types -------------------------------------------------------------
29	
30	export type ArrangementViewState = {
31	  scrollX: number;
32	  scrollY: number;
33	  pixelsPerSecond: number;
34	  trackHeight: number;
35	  headerWidth: number;
36	};
37	
38	export type RenderContext = {
39	  ctx: CanvasRenderingContext2D;
40	  width: number;
41	  height: number;
42	  view: ArrangementViewState;
43	  tracks: readonly TrackModel[];
44	  clips: Record<string, ClipModel>;
45	  selectedClipIds: readonly string[];
46	  cursorSeconds: number;
47	  bpm: number;
48	  automationLanes?: Record<string, readonly AutomationLane[]>;
49	};
50	
51	// -- Helpers ------------------------------------------------------------------
52	
53	function secondsToX(seconds: number, view: ArrangementViewState): number {
54	  return view.headerWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
55	}
56	
57	function trackY(index: number, view: ArrangementViewState): number {
58	  return RULER_HEIGHT + index * view.trackHeight - view.scrollY;
59	}
60	
61	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
62	function hexToRgba(hex: string, alpha: number): string {
63	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
64	    return `rgba(128,128,128,${String(alpha)})`;
65	  }
66	  const r = parseInt(hex.slice(1, 3), 16);
67	  const g = parseInt(hex.slice(3, 5), 16);
68	  const b = parseInt(hex.slice(5, 7), 16);
69	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
70	}
71	
72	// -- Rendering stages ---------------------------------------------------------
73	
74	function drawBackground(rc: RenderContext): void {
75	  const { ctx, width, height } = rc;
76	  ctx.fillStyle = COLOR.gray900;
77	  ctx.fillRect(0, 0, width, height);
78	}
79	
80	function drawTimeRuler(rc: RenderContext): void {
81	  const { ctx, width, view, bpm } = rc;
82	  const secPerBeat = 60 / bpm;
83	  const secPerBar = secPerBeat * 4;
84	
85	  // Ruler background
86	  ctx.fillStyle = COLOR.black;
87	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
88	
89	  // Bar labels
90	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
91	  ctx.fillStyle = COLOR.gray500;
92	  ctx.textBaseline = "middle";
93	  ctx.textAlign = "center";
94	
95	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
96	  const endSec =
97	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
98	  const endBar = Math.ceil(endSec / secPerBar) + 1;
99	
100	  for (let bar = startBar; bar < endBar; bar++) {
101	    const x = secondsToX(bar * secPerBar, view);
102	    if (x >= view.headerWidth && x <= width) {
103	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
104	    }
105	  }
106	}
107	
108	function drawGrid(rc: RenderContext): void {
109	  const { ctx, width, height, view, bpm } = rc;
110	  const secPerBeat = 60 / bpm;
111	  const secPerBar = secPerBeat * 4;
112	
113	  // Determine visible range in seconds
114	  const startSec = view.scrollX;
115	  const endSec =
116	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
117	
118	  // Determine grid step -- skip beats when zoomed out too far
119	  const minPxPerLine = 12;
120	  let step = secPerBeat;
121	  while (step * view.pixelsPerSecond < minPxPerLine) {
122	    step *= 2;
123	  }
124	
125	  const firstBeat = Math.floor(startSec / step) * step;
126	
127	  ctx.save();
128	  for (let t = firstBeat; t <= endSec; t += step) {
129	    const x = secondsToX(t, view);
130	    if (x < view.headerWidth || x > width) continue;
131	
132	    // Check if this line sits on a bar boundary (use integer arithmetic to avoid float drift)
133	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
134	    const isBar = Math.abs(t - nearestBar) < 0.001;
135	    ctx.strokeStyle = COLOR.gray700;
136	    ctx.lineWidth = isBar ? 2 : 1;
137	
138	    ctx.beginPath();
139	    ctx.moveTo(x, RULER_HEIGHT);
140	    ctx.lineTo(x, height);
141	    ctx.stroke();
142	  }
143	  ctx.restore();
144	}
145	
146	function drawTrackLanes(rc: RenderContext): void {
147	  const { ctx, width, view, tracks } = rc;
148	
149	  for (let i = 0; i < tracks.length; i++) {
150	    const y = trackY(i, view);
151	    const bottom = y + view.trackHeight;
152	
153	    if (bottom < RULER_HEIGHT || y > rc.height) continue;
154	
155	    // Lane separator
156	    ctx.strokeStyle = COLOR.gray700;
157	    ctx.lineWidth = BORDER_WIDTH;
158	    ctx.beginPath();
159	    ctx.moveTo(0, bottom);
160	    ctx.lineTo(width, bottom);
161	    ctx.stroke();
162	  }
163	}
164	
165	function drawTrackHeaders(rc: RenderContext): void {
166	  const { ctx, view, tracks } = rc;
167	
168	  for (let i = 0; i < tracks.length; i++) {
169	    const track = tracks[i];
170	    if (track === undefined) continue;
171	    const y = trackY(i, view);
172	
173	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
174	
175	    // Header background
176	    ctx.fillStyle = COLOR.black;
177	    ctx.fillRect(0, y, view.headerWidth, view.trackHeight);
178	
179	    // Color strip (4px vertical bar)
180	    ctx.fillStyle = track.color;
181	    ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
182	
183	    // Track name
184	    ctx.font = `${String(TEXT_SM)}px ${FONT_MONO}`;
185	    ctx.fillStyle = COLOR.white;
186	    ctx.textBaseline = "middle";
187	    ctx.textAlign = "left";
188	    ctx.fillText(track.name, COLOR_STRIP_WIDTH + 8, y + view.trackHeight / 2);
189	
190	    // Armed indicator (hot pink per R-STA-02)
191	    if (track.armed) {
192	      ctx.fillStyle = COLOR.pink;
193	      ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
194	    }
195	
196	    // Mute/Solo indicators
197	    const indicatorY = y + view.trackHeight / 2;
198	    ctx.font = `bold ${String(TEXT_XS)}px ${FONT_MONO}`;
199	    ctx.textAlign = "center";
200	
201	    if (track.armed) {
202	      ctx.fillStyle = COLOR.pink;
203	      ctx.fillText("R", view.headerWidth - 54, indicatorY);
204	    }
205	    if (track.muted) {
206	      ctx.fillStyle = COLOR.gray500;
207	      ctx.fillText("M", view.headerWidth - 36, indicatorY);
208	    }
209	    if (track.solo) {
210	      ctx.fillStyle = COLOR.gray500;
211	      ctx.fillText("S", view.headerWidth - 18, indicatorY);
212	    }
213	
214	    // Header right border
215	    ctx.strokeStyle = COLOR.gray700;
216	    ctx.lineWidth = BORDER_WIDTH;
217	    ctx.beginPath();
218	    ctx.moveTo(view.headerWidth, y);
219	    ctx.lineTo(view.headerWidth, y + view.trackHeight);
220	    ctx.stroke();
221	  }
222	}
223	
224	function drawClips(rc: RenderContext): void {
225	  const { ctx, view, tracks, clips, selectedClipIds } = rc;
226	  const selectedSet = new Set(selectedClipIds);
227	
228	  for (let i = 0; i < tracks.length; i++) {
229	    const track = tracks[i];
230	    if (track === undefined) continue;
231	    const y = trackY(i, view);
232	
233	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
234	
235	    for (const clipId of track.clipIds) {
236	      const clip = clips[clipId];
237	      if (clip === undefined) continue;
238	
239	      const x = secondsToX(clip.startTime, view);
240	      const w = clip.duration * view.pixelsPerSecond;
241	
242	      // Skip clips that are fully out of view
243	      if (x + w < view.headerWidth || x > rc.width) continue;
244	
245	      const clipY = y + CLIP_PADDING;
246	      const clipH = view.trackHeight - CLIP_PADDING * 2;
247	
248	      // Clip fill (track color at 60% opacity)
249	      ctx.fillStyle = hexToRgba(track.color, 0.6);
250	      ctx.fillRect(x, clipY, w, clipH);
251	
252	      // Clip border
253	      const isSelected = selectedSet.has(clip.id);
254	      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
255	      ctx.lineWidth = BORDER_WIDTH;
256	      ctx.strokeRect(x, clipY, w, clipH);
257	
258	      // Clip name label
259	      ctx.save();
260	      ctx.beginPath();
261	      ctx.rect(x, clipY, w, clipH);
262	      ctx.clip();
263	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
264	      ctx.fillStyle = COLOR.white;
265	      ctx.textBaseline = "top";
266	      ctx.textAlign = "left";
267	      ctx.fillText(clip.name, x + 4, clipY + 4);
268	      ctx.restore();
269	    }
270	  }
271	}
272	
273	const AUTOMATION_LINE_COLOR = "#00ccff";
274	const AUTOMATION_POINT_RADIUS = 3;
275	const AUTOMATION_SAMPLES_PER_PX = 4; // evaluate every 4 pixels for smooth curves
276	
277	function drawAutomationLanes(rc: RenderContext): void {
278	  const { ctx, view, tracks, automationLanes } = rc;
279	  if (!automationLanes) return;
280	
281	  for (let i = 0; i < tracks.length; i++) {
282	    const track = tracks[i];
283	    if (track === undefined) continue;
284	    const lanes = automationLanes[track.id];
285	    if (!lanes || lanes.length === 0) continue;
286	
287	    const y = trackY(i, view);
288	    const laneBottom = y + view.trackHeight;
289	    if (laneBottom < RULER_HEIGHT || y > rc.height) continue;
290	
291	    for (const lane of lanes) {
292	      if (lane.points.length === 0) continue;
293	
294	      ctx.save();
295	
296	      // Clip to track lane area (past the header)
297	      ctx.beginPath();
298	      ctx.rect(
299	        view.headerWidth,
300	        y + CLIP_PADDING,
301	        rc.width - view.headerWidth,
302	        view.trackHeight - CLIP_PADDING * 2,
303	      );
304	      ctx.clip();
305	
306	      // Draw the curve as connected line segments
307	      const startSec = view.scrollX;
308	      const endSec =
309	        view.scrollX + (rc.width - view.headerWidth) / view.pixelsPerSecond;
310	      const step = AUTOMATION_SAMPLES_PER_PX / view.pixelsPerSecond;
311	      const laneH = view.trackHeight - CLIP_PADDING * 2;
312	      const laneTop = y + CLIP_PADDING;
313	
314	      ctx.strokeStyle = AUTOMATION_LINE_COLOR;
315	      ctx.lineWidth = 1.5;
316	      ctx.beginPath();
317	
318	      let first = true;
319	      for (let t = startSec; t <= endSec; t += step) {
320	        const val = evaluateCurve(lane.points, t);
321	        const px = secondsToX(t, view);
322	        const py = laneTop + laneH * (1 - val); // 1.0 at top, 0.0 at bottom
323	        if (first) {
324	          ctx.moveTo(px, py);
325	          first = false;
326	        } else {
327	          ctx.lineTo(px, py);
328	        }
329	      }
330	      ctx.stroke();
331	
332	      // Draw point handles
333	      ctx.fillStyle = AUTOMATION_LINE_COLOR;
334	      for (const pt of lane.points) {
335	        const px = secondsToX(pt.time, view);
336	        const py = laneTop + laneH * (1 - pt.value);
337	        if (px < view.headerWidth || px > rc.width) continue;
338	
339	        ctx.beginPath();
340	        ctx.arc(px, py, AUTOMATION_POINT_RADIUS, 0, Math.PI * 2);
341	        ctx.fill();
342	      }
343	
344	      ctx.restore();
345	    }
346	  }
347	}
348	
349	function drawPlayhead(rc: RenderContext): void {
350	  const { ctx, height, view, cursorSeconds } = rc;
351	  const x = secondsToX(cursorSeconds, view);
352	
353	  if (x < view.headerWidth || x > rc.width) return;
354	
355	  ctx.strokeStyle = COLOR.red;
356	  ctx.lineWidth = 2;
357	  ctx.beginPath();
358	  ctx.moveTo(x, 0);
359	  ctx.lineTo(x, height);
360	  ctx.stroke();
361	}
362	
363	// -- Public API ---------------------------------------------------------------
364	
365	export function renderArrangement(rc: RenderContext): void {
366	  drawBackground(rc);
367	  drawTimeRuler(rc);
368	  drawGrid(rc);
369	  drawTrackLanes(rc);
370	  drawTrackHeaders(rc);
371	  drawClips(rc);
372	  drawAutomationLanes(rc);
373	  drawPlayhead(rc);
374	}
