/**
 * Synth editor panel: oscillator type selectors, filter cutoff/resonance knobs,
 * ADSR sliders, LFO rate/depth knobs.
 * Neo-brutalist styling consistent with the design system.
 */

import { useCallback } from "react";
import { tokens } from "@ui/tokens/tokens";
import { RotaryKnob } from "@ui/controls/RotaryKnob";
import { useSynthStore } from "@state/synth";
import { VirtualKeyboard } from "./VirtualKeyboard";
import { ModulationMatrix } from "./ModulationMatrix";
import type { SynthParameterMap } from "@audio/synth/synth-types";
import {
  WAVEFORM_TYPES,
  FILTER_TYPES,
  LFO_SHAPES,
} from "@audio/synth/synth-types";

type SynthEditorProps = {
  trackId: string;
  onNoteOn?: (note: number, velocity: number) => void;
  onNoteOff?: (note: number) => void;
};

// ─── Shared Styles ───

const BORDER = "var(--border)";

const sectionStyle: React.CSSProperties = {
  border: BORDER,
  padding: tokens.space[2],
  display: "flex",
  flexDirection: "column",
  gap: tokens.space[1],
};

const labelStyle: React.CSSProperties = {
  fontFamily: tokens.font.mono,
  fontSize: tokens.text.xs,
  color: tokens.color.gray300,
  textTransform: "uppercase",
  letterSpacing: "0.1em",
};

const controlRowStyle: React.CSSProperties = {
  display: "flex",
  gap: tokens.space[2],
  alignItems: "center",
};

// ─── Reusable Controls ───

function ToggleGroup<T extends string>({
  label,
  value,
  options,
  onChange,
}: {
  label: string;
  value: T;
  options: readonly T[];
  onChange: (v: T) => void;
}): React.JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
      <span style={labelStyle}>{label}</span>
      <div
        role="radiogroup"
        aria-label={label}
        data-testid={"toggle-" + label.toLowerCase().replace(/\s/g, "-")}
        style={{ display: "flex", gap: 0 }}
      >
        {options.map((opt) => {
          const active = opt === value;
          return (
            <button
              key={opt}
              role="radio"
              aria-checked={active}
              onClick={() => {
                onChange(opt);
              }}
              style={{
                fontFamily: tokens.font.mono,
                fontSize: tokens.text["2xs"],
                textTransform: "uppercase",
                border: BORDER,
                padding: "2px 4px",
                cursor: "pointer",
                backgroundColor: active
                  ? tokens.color.blue
                  : tokens.color.gray900,
                color: active ? tokens.color.white : tokens.color.gray300,
              }}
            >
              {opt}
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ─── Main Editor ───

export function SynthEditor({
  trackId,
  onNoteOn,
  onNoteOff,
}: SynthEditorProps): React.JSX.Element {
  const params = useSynthStore((s) => s.synths[trackId]?.params);
  const legato = useSynthStore((s) => s.synths[trackId]?.legato ?? false);
  const setParam = useSynthStore((s) => s.setParam);
  const setLegato = useSynthStore((s) => s.setLegato);

  const p = params ?? useSynthStore.getState().getParams(trackId);

  const set = useCallback(
    <K extends keyof SynthParameterMap>(
      key: K,
      value: SynthParameterMap[K],
    ) => {
      setParam(trackId, key, value);
    },
    [trackId, setParam],
  );

  const handleNoteOn = useCallback(
    (note: number, velocity: number) => {
      onNoteOn?.(note, velocity);
    },
    [onNoteOn],
  );

  const handleNoteOff = useCallback(
    (note: number) => {
      onNoteOff?.(note);
    },
    [onNoteOff],
  );

  return (
    <div
      data-testid="synth-editor"
      style={{
        display: "flex",
        flexDirection: "column",
        gap: tokens.space[2],
        padding: tokens.space[2],
        backgroundColor: tokens.color.gray900,
        fontFamily: tokens.font.mono,
        fontSize: tokens.text.sm,
        color: tokens.color.gray100,
        overflow: "auto",
      }}
    >
      {/* Oscillators Row */}
      <div style={{ display: "flex", gap: tokens.space[2] }}>
        {/* OSC 1 */}
        <section style={sectionStyle} data-testid="osc1-section">
          <span style={{ ...labelStyle, color: tokens.color.blue }}>OSC 1</span>
          <div style={controlRowStyle}>
            <ToggleGroup
              label="Type"
              value={p.osc1Type}
              options={WAVEFORM_TYPES}
              onChange={(v) => {
                set("osc1Type", v);
              }}
            />
            <RotaryKnob
              label="Oct"
              value={p.osc1Octave}
              min={-2}
              max={2}
              onChange={(v) => {
                set("osc1Octave", v);
              }}
            />
            <RotaryKnob
              label="Detune"
              value={p.osc1Detune}
              min={-100}
              max={100}
              valueText={`${String(p.osc1Detune)}c`}
              onChange={(v) => {
                set("osc1Detune", v);
              }}
            />
            <RotaryKnob
              label="Level"
              value={p.osc1Level}
              min={0}
              max={1}
              step={0.01}
              onChange={(v) => {
                set("osc1Level", v);
              }}
            />
          </div>
        </section>

        {/* OSC 2 */}
        <section style={sectionStyle} data-testid="osc2-section">
          <span style={{ ...labelStyle, color: tokens.color.pink }}>OSC 2</span>
          <div style={controlRowStyle}>
            <ToggleGroup
              label="Type"
              value={p.osc2Type}
              options={WAVEFORM_TYPES}
              onChange={(v) => {
                set("osc2Type", v);
              }}
            />
            <RotaryKnob
              label="Oct"
              value={p.osc2Octave}
              min={-2}
              max={2}
              onChange={(v) => {
                set("osc2Octave", v);
              }}
            />
            <RotaryKnob
              label="Detune"
              value={p.osc2Detune}
              min={-100}
              max={100}
              valueText={`${String(p.osc2Detune)}c`}
              onChange={(v) => {
                set("osc2Detune", v);
              }}
            />
            <RotaryKnob
              label="Level"
              value={p.osc2Level}
              min={0}
              max={1}
              step={0.01}
              onChange={(v) => {
                set("osc2Level", v);
              }}
            />
          </div>
        </section>
      </div>

      {/* Filter + Envelopes Row */}
      <div style={{ display: "flex", gap: tokens.space[2] }}>
        {/* Filter */}
        <section style={sectionStyle} data-testid="filter-section">
          <span style={{ ...labelStyle, color: tokens.color.green }}>
            FILTER
          </span>
          <div style={controlRowStyle}>
            <ToggleGroup
              label="Type"
              value={p.filterType}
              options={FILTER_TYPES}
              onChange={(v) => {
                set("filterType", v);
              }}
            />
            <RotaryKnob
              label="Cutoff"
              value={p.filterCutoff}
              min={20}
              max={20000}
              valueText={`${String(p.filterCutoff)}Hz`}
              onChange={(v) => {
                set("filterCutoff", v);
              }}
            />
            <RotaryKnob
              label="Reso"
              value={p.filterResonance}
              min={0.5}
              max={20}
              step={0.1}
              onChange={(v) => {
                set("filterResonance", v);
              }}
            />
            <RotaryKnob
              label="Env"
              value={p.filterEnvDepth}
              min={-60}
              max={60}
              valueText={`${p.filterEnvDepth}st`}
              onChange={(v) => {
                set("filterEnvDepth", v);
              }}
            />
          </div>
        </section>

        {/* Amp Envelope */}
        <section style={sectionStyle} data-testid="amp-env-section">
          <span style={{ ...labelStyle, color: tokens.color.amber }}>
            AMP ENV
          </span>
          <div style={controlRowStyle}>
            <RotaryKnob
              label="A"
              value={p.ampAttack}
              min={0}
              max={5}
              step={0.01}
              valueText={`${p.ampAttack.toFixed(2)}s`}
              onChange={(v) => {
                set("ampAttack", v);
              }}
            />
            <RotaryKnob
              label="D"
              value={p.ampDecay}
              min={0}
              max={5}
              step={0.01}
              valueText={`${p.ampDecay.toFixed(2)}s`}
              onChange={(v) => {
                set("ampDecay", v);
              }}
            />
            <RotaryKnob
              label="S"
              value={p.ampSustain}
              min={0}
              max={1}
              step={0.01}
              onChange={(v) => {
                set("ampSustain", v);
              }}
            />
            <RotaryKnob
              label="R"
              value={p.ampRelease}
              min={0}
              max={10}
              step={0.01}
              valueText={`${p.ampRelease.toFixed(2)}s`}
              onChange={(v) => {
                set("ampRelease", v);
              }}
            />
          </div>
        </section>

        {/* Filter Envelope */}
        <section style={sectionStyle} data-testid="filter-env-section">
          <span style={{ ...labelStyle, color: tokens.color.green }}>
            FLT ENV
          </span>
          <div style={controlRowStyle}>
            <RotaryKnob
              label="A"
              value={p.filterAttack}
              min={0}
              max={5}
              step={0.01}
              valueText={`${p.filterAttack.toFixed(2)}s`}
              onChange={(v) => {
                set("filterAttack", v);
              }}
            />
            <RotaryKnob
              label="D"
              value={p.filterDecay}
              min={0}
              max={5}
              step={0.01}
              valueText={`${p.filterDecay.toFixed(2)}s`}
              onChange={(v) => {
                set("filterDecay", v);
