              onChange={(v) => {
                set("lfo1Shape", v);
              }}
            />
            <RotaryKnob
              label="Rate"
              value={p.lfo1Rate}
              min={0.1}
              max={20}
              step={0.1}
              valueText={`${p.lfo1Rate.toFixed(1)}Hz`}
              onChange={(v) => {
                set("lfo1Rate", v);
              }}
            />
            <RotaryKnob
              label="Depth"
              value={p.lfo1Depth}
              min={0}
              max={1}
              step={0.01}
              onChange={(v) => {
                set("lfo1Depth", v);
              }}
            />
          </div>
        </section>

        {/* LFO 2 */}
        <section style={sectionStyle} data-testid="lfo2-section">
          <span style={labelStyle}>LFO 2</span>
          <div style={controlRowStyle}>
            <ToggleGroup
              label="Shape"
              value={p.lfo2Shape}
              options={LFO_SHAPES}
              onChange={(v) => {
                set("lfo2Shape", v);
              }}
            />
            <RotaryKnob
              label="Rate"
              value={p.lfo2Rate}
              min={0.1}
              max={20}
              step={0.1}
              valueText={`${p.lfo2Rate.toFixed(1)}Hz`}
              onChange={(v) => {
                set("lfo2Rate", v);
              }}
            />
            <RotaryKnob
              label="Depth"
              value={p.lfo2Depth}
              min={0}
